import{p as t,bh as a,I as i,U as r}from"./chunks/framework.BpabEsSf.js";const p=JSON.parse('{"title":"クイックスタート","description":"","frontmatter":{"title":"クイックスタート","date":"2025-05-01T23:00:00.000Z","permalink":"/guide/quickstart","categories":["ガイド"],"tags":["ガイド"],"top":true,"sticky":1},"headers":[],"relativePath":"ja/01.Guide/01.Introduction/10.Quick Start.md","filePath":"ja/01.Guide/01.Introduction/10.Quick Start.md","lastUpdated":null}'),o={name:"ja/01.Guide/01.Introduction/10.Quick Start.md"};function d(n,e,l,c,s,u){return a(),i("div",null,[...e[0]||(e[0]=[r('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /ja\\01.Guide\\01.Introduction\\10.Quick Start.md for this page in Markdown format</div><h1 id="クイックスタート" tabindex="-1">クイックスタート <a class="header-anchor" href="#クイックスタート" aria-label="Permalink to &quot;クイックスタート&quot;">​</a></h1><h3 id="迅速なインストール" tabindex="-1">迅速なインストール <a class="header-anchor" href="#迅速なインストール" aria-label="Permalink to &quot;迅速なインストール&quot;">​</a></h3><p>Android:</p><ol><li>GitHub の <a href="https://github.com/JoyinJoester/Monica/releases" target="_blank" rel="noreferrer">Releases</a> ページから最新の APK ファイルをダウンロードします。</li><li>Android 8.0 以上のデバイスにインストールし、起動後にマスターパスワードを初期設定します。</li></ol><p>ブラウザ拡張機能 (Chrome / Edge):</p><ol><li><code>Monica for Browser</code> ディレクトリ内で拡張機能をビルドします。</li><li>ブラウザで <code>chrome://extensions/</code> を開き、「デベロッパー モード」を有効にします。</li><li>「パッケージ化されていない拡張機能を読み込む」を選択し、ビルドされた <code>dist</code> ディレクトリを選択して導入します。</li></ol><h3 id="既知の制限事項" tabindex="-1">既知の制限事項 <a class="header-anchor" href="#既知の制限事項" aria-label="Permalink to &quot;既知の制限事項&quot;">​</a></h3><ul><li>システムの互換性の原因により、現在、一部のシャオミ製 HyperOS デバイスにおいて、Monica for Android からパスキー（Passkey）を正常に作成できない問題が確認されています。</li></ul>',9)])])}const _=t(o,[["render",d]]);export{p as __pageData,_ as default};
